1	const PROCESSING_FEE = 5;
2	
3	interface Item {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	}
9	
10	interface Damage {
11	  itemType: string;
12	  amount: number;
13	}
14	
15	interface Incident {
16	  cause?: string;
17	  damages: Damage[];
18	}
19	
20	interface Step {
21	  op: string;
22	  items?: Item[];
23	  policy?: number;
24	  incident?: Incident;
25	}
26	
27	interface Customer {
28	  yearsWithMHPCO: number;
29	}
30	
31	interface Scenario {
32	  customer: Customer;
33	  steps: Step[];
34	}
35	
36	const BASE_PREMIUMS: Record<string, number> = {
37	  sword: 100,
38	  amulet: 60,
39	  staff: 80,
40	  potion: 40,
41	  rune: 25,
42	  moonstone: 25,
43	};
44	
45	const INSURANCE_VALUES: Record<string, number> = {
46	  sword: 1000,
47	  amulet: 600,
48	  staff: 800,
49	  potion: 400,
50	  rune: 250,
51	  moonstone: 250,
52	};
53	
54	const DEDUCTIBLE = 100;
55	const CAP_MULTIPLIER = 2;
56	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
57	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
58	
59	const basePremium = (item: Item): number => {
60	  if (!(item.type in BASE_PREMIUMS)) {
61	    throw new Error(`Unknown item type: ${item.type}`);
62	  }
63	  return BASE_PREMIUMS[item.type];
64	};
65	
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	const BLOCK_SIZE = 3;
68	const BLOCK_PRICE = 60;
69	
70	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
71	
72	const countByType = (items: Item[]): Record<string, number> =>
73	  items.reduce<Record<string, number>>((counts, item) => {
74	    counts[item.type] = (counts[item.type] ?? 0) + 1;
75	    return counts;
76	  }, {});
77	
78	const componentGroupPremium = (type: string, count: number): number =>
79	  count === BLOCK_SIZE ? BLOCK_PRICE : count * basePremium({ type });
80	
81	const componentsPremium = (components: Item[]): number => {
82	  const counts = countByType(components);
83	  return Object.entries(counts).reduce(
84	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
85	    0,
86	  );
87	};
88	
89	const CURSED_SURCHARGE_RATE = 0.5;
90	const HIGH_ENCHANTMENT_THRESHOLD = 5;
91	const HIGH_ENCHANTMENT_RATE = 0.3;
92	const FIRST_INSURANCE_RATE = 0.1;
93	const LOYALTY_YEARS_THRESHOLD = 2;
94	const LOYALTY_DISCOUNT_RATE = 0.2;
95	const FOLLOWUP_DISCOUNT_RATE = 0.15;
96	
97	const itemSurcharges = (item: Item): number => {
98	  const base = basePremium(item);
99	  let extras = 0;
100	  if (item.cursed) extras += base * CURSED_SURCHARGE_RATE;
101	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
102	    extras += base * HIGH_ENCHANTMENT_RATE;
103	  }
104	  return extras;
105	};
106	
107	interface PremiumBreakdown {
108	  withSurcharges: number;
109	  baseOnly: number;
110	}
111	
112	const sumBy = <T>(items: T[], f: (item: T) => number): number =>
113	  items.reduce((sum, item) => sum + f(item), 0);
114	
115	const itemsPremiumBreakdown = (items: Item[]): PremiumBreakdown => {
116	  const mainItems = items.filter((i) => !isComponent(i));
117	  const componentsTotal = componentsPremium(items.filter(isComponent));
118	  const mainBase = sumBy(mainItems, basePremium);
119	  const mainSurcharges = sumBy(mainItems, itemSurcharges);
120	  return {
121	    withSurcharges: mainBase + mainSurcharges + componentsTotal,
122	    baseOnly: mainBase + componentsTotal,
123	  };
124	};
125	
126	const policyModifiers = (
127	  customer: Customer,
128	  policyBase: number,
129	  isFollowUp: boolean,
130	): number => {
131	  let modifiers = policyBase * FIRST_INSURANCE_RATE;
132	  if (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
133	    modifiers -= policyBase * LOYALTY_DISCOUNT_RATE;
134	  }
135	  if (isFollowUp) {
136	    modifiers -= policyBase * FOLLOWUP_DISCOUNT_RATE;
137	  }
138	  return modifiers;
139	};
140	
141	const computeQuotePremium = (
142	  customer: Customer,
143	  items: Item[],
144	  isFollowUp: boolean,
145	): number => {
146	  const { withSurcharges, baseOnly } = itemsPremiumBreakdown(items);
147	  const raw = withSurcharges + policyModifiers(customer, baseOnly, isFollowUp) + PROCESSING_FEE;
148	  return Math.ceil(raw);
149	};
150	
151	interface Policy {
152	  items: Item[];
153	  remainingCap: number;
154	}
155	
156	const policyInsuranceSum = (items: Item[]): number =>
157	  sumBy(items, (item) => INSURANCE_VALUES[item.type]);
158	
159	const buildPolicy = (items: Item[]): Policy => ({
160	  items,
161	  remainingCap: policyInsuranceSum(items) * CAP_MULTIPLIER,
162	});
163	
164	const isHighEnchantmentForPayout = (item: Item): boolean =>
165	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
166	
167	const reimbursableAmount = (item: Item, damageAmount: number): number =>
168	  isHighEnchantmentForPayout(item)
169	    ? damageAmount * HIGH_ENCHANTMENT_PAYOUT_RATE
170	    : damageAmount;
171	
172	const damagePayout = (item: Item, damageAmount: number): number =>
173	  reimbursableAmount(item, damageAmount) - DEDUCTIBLE;
174	
175	const consumeMatchingItem = (pool: Item[], itemType: string): Item => {
176	  const index = pool.findIndex((item) => item.type === itemType);
177	  if (index === -1) {
178	    throw new Error(`Damage references item not in policy: ${itemType}`);
179	  }
180	  const [matched] = pool.splice(index, 1);
181	  return matched;
182	};
183	
184	const rawIncidentPayout = (items: Item[], damages: Damage[]): number => {
185	  const insuredItems = [...items];
186	  return damages.reduce((sum, damage) => {
187	    if (damage.amount < 0) {
188	      throw new Error(`Damage amount must be non-negative: ${damage.amount}`);
189	    }
190	    const item = consumeMatchingItem(insuredItems, damage.itemType);
191	    return sum + damagePayout(item, damage.amount);
192	  }, 0);
193	};
194	
195	const applyCap = (policy: Policy, rawPayout: number): number => {
196	  const cappedPayout = Math.min(rawPayout, policy.remainingCap);
197	  policy.remainingCap -= cappedPayout;
198	  return cappedPayout;
199	};
200	
201	const computeClaim = (
202	  policy: Policy,
203	  incident: Incident,
204	): { payout: number; remainingCap: number } => {
205	  const cappedPayout = applyCap(policy, rawIncidentPayout(policy.items, incident.damages));
206	  return {
207	    payout: Math.floor(cappedPayout),
208	    remainingCap: policy.remainingCap,
209	  };
210	};
211	
212	export const runScenario = (scenario: Scenario): unknown => {
213	  const policies: Policy[] = [];
214	  const results = scenario.steps.map((step) => {
215	    if (step.op === "claim") {
216	      return computeClaim(policies[step.policy ?? 0], step.incident as Incident);
217	    }
218	    const items = step.items ?? [];
219	    const isFollowUp = policies.length > 0;
220	    policies.push(buildPolicy(items));
221	    return { premium: computeQuotePremium(scenario.customer, items, isFollowUp) };
222	  });
223	  return { results };
224	};
